import{_ as s,c as e,o,a1 as a}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"AI 代理: 10 位專家介紹 | oh-my-opencode","description":"學習 oh-my-opencode 的 10 個 AI 代理。根據任務類型選擇代理，實現高效協作與平行執行。","frontmatter":{"title":"AI 代理: 10 位專家介紹 | oh-my-opencode","sidebarTitle":"認識 10 位 AI 專家","subtitle":"AI 代理: 10 位專家介紹","description":"學習 oh-my-opencode 的 10 個 AI 代理。根據任務類型選擇代理，實現高效協作與平行執行。","tags":["ai-agents","orchestration"],"prerequisite":["start-sisyphus-orchestrator"],"order":60},"headers":[],"relativePath":"zh-tw/code-yeongyu/oh-my-opencode/advanced/ai-agents-overview/index.md","filePath":"zh-tw/code-yeongyu/oh-my-opencode/advanced/ai-agents-overview/index.md"}'),n={name:"zh-tw/code-yeongyu/oh-my-opencode/advanced/ai-agents-overview/index.md"};function r(l,t,i,d,p,g){return o(),e("div",null,[...t[0]||(t[0]=[a(`<h1 id="ai-代理團隊-10-位專家介紹" tabindex="-1">AI 代理團隊：10 位專家介紹 <a class="header-anchor" href="#ai-代理團隊-10-位專家介紹" aria-label="Permalink to &quot;AI 代理團隊：10 位專家介紹&quot;">​</a></h1><h2 id="學完你能做什麼" tabindex="-1">學完你能做什麼 <a class="header-anchor" href="#學完你能做什麼" aria-label="Permalink to &quot;學完你能做什麼&quot;">​</a></h2><ul><li>了解 10 個內建 AI 代理的職責和專長</li><li>根據任務類型快速選擇最合適的代理</li><li>理解代理之間的協作機制（委派、平行、審查）</li><li>掌握不同代理的權限限制和使用情境</li></ul><h2 id="核心思路-像真實團隊一樣協作" tabindex="-1">核心思路：像真實團隊一樣協作 <a class="header-anchor" href="#核心思路-像真實團隊一樣協作" aria-label="Permalink to &quot;核心思路：像真實團隊一樣協作&quot;">​</a></h2><p><strong>oh-my-opencode</strong> 的核心思想是：<strong>不要把 AI 當成一個全能助手，而是當成一個專業團隊</strong>。</p><p>真實開發團隊裡，你需要：</p><ul><li><strong>主編排器</strong>（Tech Lead）：負責規劃、分配任務、追蹤進度</li><li><strong>架構顧問</strong>（Architect）：提供技術決策和架構設計建議</li><li><strong>程式碼審查</strong>（Reviewer）：檢查程式碼品質，發現潛在問題</li><li><strong>研究專家</strong>（Researcher）：查找文件、搜尋開源實作、調研最佳實踐</li><li><strong>程式碼偵探</strong>（Searcher）：快速定位程式碼、查找引用、理解現有實作</li><li><strong>前端設計師</strong>（Frontend Designer）：設計 UI、調整樣式</li><li><strong>Git 專家</strong>（Git Master）：提交程式碼、管理分支、搜尋歷史</li></ul><p>oh-my-opencode 把這些角色做成了 10 個專業 AI 代理，你可以根據任務類型靈活組合使用。</p><h2 id="_10-個代理詳解" tabindex="-1">10 個代理詳解 <a class="header-anchor" href="#_10-個代理詳解" aria-label="Permalink to &quot;10 個代理詳解&quot;">​</a></h2><h3 id="主編排器-2-個" tabindex="-1">主編排器（2 個） <a class="header-anchor" href="#主編排器-2-個" aria-label="Permalink to &quot;主編排器（2 個）&quot;">​</a></h3><h4 id="sisyphus-主編排器" tabindex="-1">Sisyphus - 主編排器 <a class="header-anchor" href="#sisyphus-主編排器" aria-label="Permalink to &quot;Sisyphus - 主編排器&quot;">​</a></h4><p><strong>角色</strong>：主編排器，你的首要技術負責人</p><p><strong>能力</strong>：</p><ul><li>深度推理（32k thinking budget）</li><li>規劃和委派複雜任務</li><li>執行程式碼修改和重構</li><li>管理整個開發流程</li></ul><p><strong>推薦模型</strong>：<code>anthropic/claude-opus-4-5</code>（temperature: 0.1）</p><p><strong>使用情境</strong>：</p><ul><li>日常開發任務（新增功能、修復 bug）</li><li>需要深度推理的複雜問題</li><li>多步驟任務分解和執行</li><li>需要平行委派其他代理的情境</li></ul><p><strong>呼叫方式</strong>：</p><ul><li>預設主代理（OpenCode Agent 選擇器中的 &quot;Sisyphus&quot;）</li><li>提示詞中直接輸入任務，無需特殊觸發詞</li></ul><p><strong>權限</strong>：完整工具權限（write、edit、bash、delegate_task 等）</p><hr><h4 id="atlas-todo-管理器" tabindex="-1">Atlas - TODO 管理器 <a class="header-anchor" href="#atlas-todo-管理器" aria-label="Permalink to &quot;Atlas - TODO 管理器&quot;">​</a></h4><p><strong>角色</strong>：主編排器，專注 TODO 清單管理和任務執行追蹤</p><p><strong>能力</strong>：</p><ul><li>管理和追蹤 TODO 清單</li><li>系統化執行計畫</li><li>任務進度監控</li></ul><p><strong>推薦模型</strong>：<code>anthropic/claude-opus-4-5</code>（temperature: 0.1）</p><p><strong>使用情境</strong>：</p><ul><li>使用 <code>/start-work</code> 指令啟動專案執行</li><li>需要嚴格按照計畫完成任務</li><li>系統化追蹤任務進度</li></ul><p><strong>呼叫方式</strong>：</p><ul><li>使用斜線指令 <code>/start-work</code></li><li>透過 Atlas Hook 自動啟動</li></ul><p><strong>權限</strong>：完整工具權限</p><hr><h3 id="顧問與審查-3-個" tabindex="-1">顧問與審查（3 個） <a class="header-anchor" href="#顧問與審查-3-個" aria-label="Permalink to &quot;顧問與審查（3 個）&quot;">​</a></h3><h4 id="oracle-策略顧問" tabindex="-1">Oracle - 策略顧問 <a class="header-anchor" href="#oracle-策略顧問" aria-label="Permalink to &quot;Oracle - 策略顧問&quot;">​</a></h4><p><strong>角色</strong>：唯讀技術顧問，高智商推理專家</p><p><strong>能力</strong>：</p><ul><li>架構決策建議</li><li>複雜問題診斷</li><li>程式碼審查（唯讀）</li><li>多系統權衡分析</li></ul><p><strong>推薦模型</strong>：<code>openai/gpt-5.2</code>（temperature: 0.1）</p><p><strong>使用情境</strong>：</p><ul><li>複雜架構設計</li><li>完成重要工作後的自我審查</li><li>2 次以上修復失敗的困難除錯</li><li>陌生的程式碼模式或架構</li><li>安全性/效能相關問題</li></ul><p><strong>觸發條件</strong>：</p><ul><li>提示詞中包含 <code>@oracle</code> 或使用 <code>delegate_task(agent=&quot;oracle&quot;)</code></li><li>複雜架構決策時自動推薦</li></ul><p><strong>限制</strong>：唯讀權限（禁止 write、edit、task、delegate_task）</p><p><strong>核心原則</strong>：</p><ul><li><strong>極簡主義</strong>：傾向於最簡單的解決方案</li><li><strong>利用現有資源</strong>：優先修改當前程式碼，避免引入新依賴</li><li><strong>開發者體驗優先</strong>：可讀性、可維護性 &gt; 理論效能</li><li><strong>單一明確路徑</strong>：提供一個主要建議，僅在權衡差異顯著時提替代方案</li></ul><hr><h4 id="metis-前規劃分析師" tabindex="-1">Metis - 前規劃分析師 <a class="header-anchor" href="#metis-前規劃分析師" aria-label="Permalink to &quot;Metis - 前規劃分析師&quot;">​</a></h4><p><strong>角色</strong>：規劃前的需求分析和風險評估專家</p><p><strong>能力</strong>：</p><ul><li>識別隱藏需求和未明確要求</li><li>檢測可能導致 AI 失敗的模糊性</li><li>標記潛在 AI-slop 模式（過度工程化、範圍蔓延）</li><li>為規劃代理準備指令</li></ul><p><strong>推薦模型</strong>：<code>anthropic/claude-sonnet-4-5</code>（temperature: 0.3）</p><p><strong>使用情境</strong>：</p><ul><li>在 Prometheus 規劃之前</li><li>當使用者請求模糊或開放時</li><li>防止 AI 過度工程化模式</li></ul><p><strong>呼叫方式</strong>：Prometheus 自動呼叫（面試模式）</p><p><strong>限制</strong>：唯讀權限（禁止 write、edit、task、delegate_task）</p><p><strong>核心流程</strong>：</p><ol><li><strong>意圖分類</strong>：重構 / 從零建構 / 中等任務 / 協作 / 架構 / 研究</li><li><strong>意圖特定分析</strong>：根據不同類型提供針對性建議</li><li><strong>問題生成</strong>：為使用者生成明確問題</li><li><strong>指令準備</strong>：為 Prometheus 生成明確的 &quot;MUST&quot; 和 &quot;MUST NOT&quot; 指令</li></ol><hr><h4 id="momus-計畫審查者" tabindex="-1">Momus - 計畫審查者 <a class="header-anchor" href="#momus-計畫審查者" aria-label="Permalink to &quot;Momus - 計畫審查者&quot;">​</a></h4><p><strong>角色</strong>：嚴格的計畫評審專家，發現所有遺漏和模糊點</p><p><strong>能力</strong>：</p><ul><li>驗證計畫的清晰度、可驗證性和完整性</li><li>檢查所有檔案引用和上下文</li><li>模擬實際實作步驟</li><li>識別關鍵遺漏</li></ul><p><strong>推薦模型</strong>：<code>anthropic/claude-sonnet-4-5</code>（temperature: 0.1）</p><p><strong>使用情境</strong>：</p><ul><li>Prometheus 建立工作計畫後</li><li>執行複雜 TODO 清單之前</li><li>驗證計畫品質</li></ul><p><strong>呼叫方式</strong>：Prometheus 自動呼叫</p><p><strong>限制</strong>：唯讀權限（禁止 write、edit、task、delegate_task）</p><p><strong>四大評審標準</strong>：</p><ol><li><strong>工作內容清晰度</strong>：每個任務是否指定了參考來源？</li><li><strong>驗證與驗收標準</strong>：是否有具體的成功驗證方法？</li><li><strong>上下文完整性</strong>：是否提供足夠上下文（90% 信心度閾值）？</li><li><strong>整體理解</strong>：開發者是否理解 WHY、WHAT 和 HOW？</li></ol><p><strong>核心原則</strong>：<strong>文件評審者，不是設計顧問</strong>。評估的是「計畫是否清楚到可以執行」，而不是「選擇的方法是否正確」。</p><hr><h3 id="研究與探索-3-個" tabindex="-1">研究與探索（3 個） <a class="header-anchor" href="#研究與探索-3-個" aria-label="Permalink to &quot;研究與探索（3 個）&quot;">​</a></h3><h4 id="librarian-多儲存庫研究專家" tabindex="-1">Librarian - 多儲存庫研究專家 <a class="header-anchor" href="#librarian-多儲存庫研究專家" aria-label="Permalink to &quot;Librarian - 多儲存庫研究專家&quot;">​</a></h4><p><strong>角色</strong>：開源程式碼庫理解專家，專門查找文件和實作範例</p><p><strong>能力</strong>：</p><ul><li>GitHub CLI：複製儲存庫、搜尋 issues/PRs、查看歷史</li><li>Context7：查詢官方文件</li><li>Web Search：搜尋最新資訊</li><li>生成帶永久連結的證據</li></ul><p><strong>推薦模型</strong>：<code>opencode/big-pickle</code>（temperature: 0.1）</p><p><strong>使用情境</strong>：</p><ul><li>「如何使用 [函式庫]？」</li><li>「[框架特性] 的最佳實踐是什麼？」</li><li>「[外部依賴] 為什麼會這樣表現？」</li><li>「查找 [函式庫] 的使用範例」</li></ul><p><strong>觸發條件</strong>：</p><ul><li>提及外部函式庫/來源時自動觸發</li><li>提示詞中包含 <code>@librarian</code></li></ul><p><strong>請求類型分類</strong>：</p><ul><li><strong>Type A（概念性）</strong>：「如何做 X？」、「最佳實踐」</li><li><strong>Type B（實作參考）</strong>：「X 如何實作 Y？」、「顯示 Z 的原始碼」</li><li><strong>Type C（上下文與歷史）</strong>：「為什麼會這樣改？」、「X 的歷史？」</li><li><strong>Type D（綜合研究）</strong>：複雜/模糊請求</li></ul><p><strong>限制</strong>：唯讀權限（禁止 write、edit、task、delegate_task、call_omo_agent）</p><p><strong>強制要求</strong>：所有程式碼聲明必須包含 GitHub 永久連結</p><hr><h4 id="explore-快速程式碼庫探索專家" tabindex="-1">Explore - 快速程式碼庫探索專家 <a class="header-anchor" href="#explore-快速程式碼庫探索專家" aria-label="Permalink to &quot;Explore - 快速程式碼庫探索專家&quot;">​</a></h4><p><strong>角色</strong>：上下文感知的程式碼搜尋專家</p><p><strong>能力</strong>：</p><ul><li>LSP 工具：定義、引用、符號導覽</li><li>AST-Grep：結構模式搜尋</li><li>Grep：文字模式搜尋</li><li>Glob：檔案名稱模式比對</li><li>平行執行（3+ 工具同時執行）</li></ul><p><strong>推薦模型</strong>：<code>opencode/gpt-5-nano</code>（temperature: 0.1）</p><p><strong>使用情境</strong>：</p><ul><li>需要 2+ 個搜尋角度的廣泛搜尋</li><li>不熟悉的模組結構</li><li>跨層模式發現</li><li>查找「X 在哪裡？」、「哪個檔案有 Y？」</li></ul><p><strong>觸發條件</strong>：</p><ul><li>涉及 2+ 個模組時自動觸發</li><li>提示詞中包含 <code>@explore</code></li></ul><p><strong>強制輸出格式</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;analysis&gt;</span></span>
<span class="line"><span>**Literal Request**: [使用者字面請求]</span></span>
<span class="line"><span>**Actual Need**: [實際需要什麼]</span></span>
<span class="line"><span>**Success Looks Like**: [成功應該是什麼樣]</span></span>
<span class="line"><span>&lt;/analysis&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;results&gt;</span></span>
<span class="line"><span>&lt;files&gt;</span></span>
<span class="line"><span>- /absolute/path/to/file1.ts — [為什麼這個檔案相關]</span></span>
<span class="line"><span>- /absolute/path/to/file2.ts — [為什麼這個檔案相關]</span></span>
<span class="line"><span>&lt;/files&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;answer&gt;</span></span>
<span class="line"><span>[直接回答實際需求]</span></span>
<span class="line"><span>&lt;/answer&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;next_steps&gt;</span></span>
<span class="line"><span>[接下來應該做什麼]</span></span>
<span class="line"><span>&lt;/next_steps&gt;</span></span>
<span class="line"><span>&lt;/results&gt;</span></span></code></pre></div><p><strong>限制</strong>：唯讀權限（禁止 write、edit、task、delegate_task、call_omo_agent）</p><hr><h4 id="multimodal-looker-媒體分析專家" tabindex="-1">Multimodal Looker - 媒體分析專家 <a class="header-anchor" href="#multimodal-looker-媒體分析專家" aria-label="Permalink to &quot;Multimodal Looker - 媒體分析專家&quot;">​</a></h4><p><strong>角色</strong>：解釋無法作為純文字讀取的媒體檔案</p><p><strong>能力</strong>：</p><ul><li>PDF：擷取文字、結構、表格、特定章節資料</li><li>圖片：描述版面配置、UI 元素、文字、圖表</li><li>圖表：解釋關係、流程、架構</li></ul><p><strong>推薦模型</strong>：<code>google/gemini-3-flash</code>（temperature: 0.1）</p><p><strong>使用情境</strong>：</p><ul><li>需要從 PDF 擷取結構化資料</li><li>描述圖片中的 UI 元素或圖表</li><li>解析技術文件中的圖表</li></ul><p><strong>呼叫方式</strong>：透過 <code>look_at</code> 工具自動觸發</p><p><strong>限制</strong>：<strong>唯讀白名單</strong>（僅允許 read 工具）</p><hr><h3 id="規劃與執行-2-個" tabindex="-1">規劃與執行（2 個） <a class="header-anchor" href="#規劃與執行-2-個" aria-label="Permalink to &quot;規劃與執行（2 個）&quot;">​</a></h3><h4 id="prometheus-策略規劃師" tabindex="-1">Prometheus - 策略規劃師 <a class="header-anchor" href="#prometheus-策略規劃師" aria-label="Permalink to &quot;Prometheus - 策略規劃師&quot;">​</a></h4><p><strong>角色</strong>：面試式需求收集和工作計畫生成專家</p><p><strong>能力</strong>：</p><ul><li>面試模式：持續提問直到需求明確</li><li>工作計畫生成：結構化的 Markdown 計畫文件</li><li>平行委派：諮詢 Oracle、Metis、Momus 驗證計畫</li></ul><p><strong>推薦模型</strong>：<code>anthropic/claude-opus-4-5</code>（temperature: 0.1）</p><p><strong>使用情境</strong>：</p><ul><li>為複雜專案制定詳細計畫</li><li>需要明確需求的專案</li><li>系統化工作流程</li></ul><p><strong>呼叫方式</strong>：</p><ul><li>提示詞中包含 <code>@prometheus</code> 或「使用 Prometheus」</li><li>使用斜線指令 <code>/start-work</code></li></ul><p><strong>工作流程</strong>：</p><ol><li><strong>面試模式</strong>：持續提問直到需求清晰</li><li><strong>起草計畫</strong>：生成結構化 Markdown 計畫</li><li><strong>平行委派</strong>： <ul><li><code>delegate_task(agent=&quot;oracle&quot;, prompt=&quot;審查架構決策&quot;)</code> → 背景執行</li><li><code>delegate_task(agent=&quot;metis&quot;, prompt=&quot;識別潛在風險&quot;)</code> → 背景執行</li><li><code>delegate_task(agent=&quot;momus&quot;, prompt=&quot;驗證計畫完整性&quot;)</code> → 背景執行</li></ul></li><li><strong>整合回饋</strong>：完善計畫</li><li><strong>輸出計畫</strong>：儲存到 <code>.sisyphus/plans/{name}.md</code></li></ol><p><strong>限制</strong>：僅規劃，不實作程式碼（由 <code>prometheus-md-only</code> Hook 強制）</p><hr><h4 id="sisyphus-junior-任務執行器" tabindex="-1">Sisyphus Junior - 任務執行器 <a class="header-anchor" href="#sisyphus-junior-任務執行器" aria-label="Permalink to &quot;Sisyphus Junior - 任務執行器&quot;">​</a></h4><p><strong>角色</strong>：類別生成的子代理執行器</p><p><strong>能力</strong>：</p><ul><li>繼承 Category 設定（模型、temperature、prompt_append）</li><li>載入 Skills（專業技能）</li><li>執行委派的子任務</li></ul><p><strong>推薦模型</strong>：繼承自 Category（預設 <code>anthropic/claude-sonnet-4-5</code>）</p><p><strong>使用情境</strong>：</p><ul><li>使用 <code>delegate_task(category=&quot;...&quot;, skills=[&quot;...&quot;])</code> 時自動生成</li><li>需要特定 Category 和 Skill 組合的任務</li><li>輕量級快速任務（&quot;quick&quot; Category 使用 Haiku 模型）</li></ul><p><strong>呼叫方式</strong>：透過 <code>delegate_task</code> 工具自動生成</p><p><strong>限制</strong>：禁止 task、delegate_task（不能再次委派）</p><hr><h2 id="代理呼叫方式速查" tabindex="-1">代理呼叫方式速查 <a class="header-anchor" href="#代理呼叫方式速查" aria-label="Permalink to &quot;代理呼叫方式速查&quot;">​</a></h2><table tabindex="0"><thead><tr><th>代理</th><th>呼叫方式</th><th>觸發條件</th></tr></thead><tbody><tr><td><strong>Sisyphus</strong></td><td>預設主代理</td><td>日常開發任務</td></tr><tr><td><strong>Atlas</strong></td><td><code>/start-work</code> 指令</td><td>啟動專案執行</td></tr><tr><td><strong>Oracle</strong></td><td><code>@oracle</code> 或 <code>delegate_task(agent=&quot;oracle&quot;)</code></td><td>複雜架構決策、2+ 次修復失敗</td></tr><tr><td><strong>Librarian</strong></td><td><code>@librarian</code> 或 <code>delegate_task(agent=&quot;librarian&quot;)</code></td><td>提及外部函式庫/來源時自動觸發</td></tr><tr><td><strong>Explore</strong></td><td><code>@explore</code> 或 <code>delegate_task(agent=&quot;explore&quot;)</code></td><td>2+ 模組涉及時自動觸發</td></tr><tr><td><strong>Multimodal Looker</strong></td><td><code>look_at</code> 工具</td><td>需要分析 PDF/圖片時</td></tr><tr><td><strong>Prometheus</strong></td><td><code>@prometheus</code> 或 <code>/start-work</code></td><td>提示詞中包含「Prometheus」或需要規劃</td></tr><tr><td><strong>Metis</strong></td><td>Prometheus 自動呼叫</td><td>規劃前自動分析</td></tr><tr><td><strong>Momus</strong></td><td>Prometheus 自動呼叫</td><td>計畫生成後自動審查</td></tr><tr><td><strong>Sisyphus Junior</strong></td><td><code>delegate_task(category=...)</code></td><td>使用 Category/Skill 時自動生成</td></tr></tbody></table><hr><h2 id="什麼時候用哪個代理" tabindex="-1">什麼時候用哪個代理 <a class="header-anchor" href="#什麼時候用哪個代理" aria-label="Permalink to &quot;什麼時候用哪個代理&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">快速決策樹</p><p><strong>情境 1：日常開發（寫程式碼、修 bug）</strong> → <strong>Sisyphus</strong>（預設）</p><p><strong>情境 2：複雜架構決策</strong> → <strong>@oracle</strong> 諮詢</p><p><strong>情境 3：需要查找外部函式庫的文件或實作</strong> → <strong>@librarian</strong> 或自動觸發</p><p><strong>情境 4：不熟悉的程式碼庫，需要找相關程式碼</strong> → <strong>@explore</strong> 或自動觸發（2+ 模組）</p><p><strong>情境 5：複雜專案需要詳細計畫</strong> → <strong>@prometheus</strong> 或使用 <code>/start-work</code></p><p><strong>情境 6：需要分析 PDF 或圖片</strong> → <strong>look_at</strong> 工具（自動觸發 Multimodal Looker）</p><p><strong>情境 7：快速簡單任務，想省錢</strong> → <code>delegate_task(category=&quot;quick&quot;)</code></p><p><strong>情境 8：需要 Git 專業操作</strong> → <code>delegate_task(category=&quot;quick&quot;, skills=[&quot;git-master&quot;])</code></p><p><strong>情境 9：需要前端 UI 設計</strong> → <code>delegate_task(category=&quot;visual-engineering&quot;)</code></p><p><strong>情境 10：需要高智商推理任務</strong> → <code>delegate_task(category=&quot;ultrabrain&quot;)</code></p></div><hr><h2 id="代理協作範例-完整工作流" tabindex="-1">代理協作範例：完整工作流 <a class="header-anchor" href="#代理協作範例-完整工作流" aria-label="Permalink to &quot;代理協作範例：完整工作流&quot;">​</a></h2><h3 id="範例-1-複雜功能開發" tabindex="-1">範例 1：複雜功能開發 <a class="header-anchor" href="#範例-1-複雜功能開發" aria-label="Permalink to &quot;範例 1：複雜功能開發&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>使用者：開發一個使用者認證系統</span></span>
<span class="line"><span></span></span>
<span class="line"><span>→ Sisyphus 接收任務</span></span>
<span class="line"><span>  → 分析需求，發現需要外部函式庫（JWT）</span></span>
<span class="line"><span>  → 平行委派：</span></span>
<span class="line"><span>    - @librarian: &quot;查找 Next.js JWT 最佳實踐&quot; → [背景]</span></span>
<span class="line"><span>    - @explore: &quot;查找現有認證相關程式碼&quot; → [背景]</span></span>
<span class="line"><span>  → 等待結果，整合資訊</span></span>
<span class="line"><span>  → 實作 JWT 認證功能</span></span>
<span class="line"><span>  → 完成後委派：</span></span>
<span class="line"><span>    - @oracle: &quot;審查架構設計&quot; → [背景]</span></span>
<span class="line"><span>  → 根據建議最佳化</span></span></code></pre></div><hr><h3 id="範例-2-專案規劃" tabindex="-1">範例 2：專案規劃 <a class="header-anchor" href="#範例-2-專案規劃" aria-label="Permalink to &quot;範例 2：專案規劃&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>使用者：使用 Prometheus 規劃這個專案</span></span>
<span class="line"><span></span></span>
<span class="line"><span>→ Prometheus 接收任務</span></span>
<span class="line"><span>  → 面試模式：</span></span>
<span class="line"><span>    - 問題 1：核心功能是什麼？</span></span>
<span class="line"><span>    - [使用者回答]</span></span>
<span class="line"><span>    - 問題 2：目標使用者群體？</span></span>
<span class="line"><span>    - [使用者回答]</span></span>
<span class="line"><span>    - ...</span></span>
<span class="line"><span>  → 需求明確後，平行委派：</span></span>
<span class="line"><span>    - delegate_task(agent=&quot;oracle&quot;, prompt=&quot;審查架構決策&quot;) → [背景]</span></span>
<span class="line"><span>    - delegate_task(agent=&quot;metis&quot;, prompt=&quot;識別潛在風險&quot;) → [背景]</span></span>
<span class="line"><span>    - delegate_task(agent=&quot;momus&quot;, prompt=&quot;驗證計畫完整性&quot;) → [背景]</span></span>
<span class="line"><span>  → 等待所有背景任務完成</span></span>
<span class="line"><span>  → 整合回饋，完善計畫</span></span>
<span class="line"><span>  → 輸出 Markdown 計畫文件</span></span>
<span class="line"><span>→ 使用者查看計畫，確認</span></span>
<span class="line"><span>→ 使用 /start-work 啟動執行</span></span></code></pre></div><hr><h2 id="代理權限與限制" tabindex="-1">代理權限與限制 <a class="header-anchor" href="#代理權限與限制" aria-label="Permalink to &quot;代理權限與限制&quot;">​</a></h2><table tabindex="0"><thead><tr><th>代理</th><th>write</th><th>edit</th><th>bash</th><th>delegate_task</th><th>webfetch</th><th>read</th><th>LSP</th><th>AST-Grep</th></tr></thead><tbody><tr><td><strong>Sisyphus</strong></td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Atlas</strong></td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Oracle</strong></td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Librarian</strong></td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Explore</strong></td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Multimodal Looker</strong></td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Prometheus</strong></td><td>❌</td><td>❌</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Metis</strong></td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Momus</strong></td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Sisyphus Junior</strong></td><td>✅</td><td>✅</td><td>✅</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr></tbody></table><hr><h2 id="本課小結" tabindex="-1">本課小結 <a class="header-anchor" href="#本課小結" aria-label="Permalink to &quot;本課小結&quot;">​</a></h2><p>oh-my-opencode 的 10 個 AI 代理涵蓋了開發流程的所有環節：</p><ul><li><strong>編排與執行</strong>：Sisyphus（主編排器）、Atlas（TODO 管理）</li><li><strong>顧問與審查</strong>：Oracle（策略顧問）、Metis（前規劃分析）、Momus（計畫審查）</li><li><strong>研究與探索</strong>：Librarian（多儲存庫研究）、Explore（程式碼庫探索）、Multimodal Looker（媒體分析）</li><li><strong>規劃</strong>：Prometheus（策略規劃）、Sisyphus Junior（子任務執行）</li></ul><p><strong>核心要點</strong>：</p><ol><li>不要把 AI 當全能助手，要當成專業團隊</li><li>根據任務類型選擇最合適的代理</li><li>利用平行委派提升效率（Librarian、Explore、Oracle 都可背景執行）</li><li>理解每個代理的權限限制（唯讀代理不能修改程式碼）</li><li>代理之間協作可以形成完整工作流（規劃 → 執行 → 審查）</li></ol><hr><h2 id="下一課預告" tabindex="-1">下一課預告 <a class="header-anchor" href="#下一課預告" aria-label="Permalink to &quot;下一課預告&quot;">​</a></h2><blockquote><p>下一課我們學習 <strong><a href="./../prometheus-planning/">Prometheus 規劃：面試式需求收集</a></strong>。</p><p>你會學到：</p><ul><li>如何使用 Prometheus 進行面試式需求收集</li><li>如何生成結構化的工作計畫</li><li>如何讓 Metis 和 Momus 驗證計畫</li><li>如何取得和取消背景任務</li></ul></blockquote><hr><h2 id="附錄-原始碼參考" tabindex="-1">附錄：原始碼參考 <a class="header-anchor" href="#附錄-原始碼參考" aria-label="Permalink to &quot;附錄：原始碼參考&quot;">​</a></h2><details><summary><strong>點擊展開查看原始碼位置</strong></summary><blockquote><p>更新時間：2026-01-26</p></blockquote><table tabindex="0"><thead><tr><th>代理</th><th>檔案路徑</th><th>行號</th></tr></thead><tbody><tr><td>Sisyphus 主編排器</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/sisyphus.ts" target="_blank" rel="noreferrer"><code>src/agents/sisyphus.ts</code></a></td><td>-</td></tr><tr><td>Atlas 主編排器</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/atlas.ts" target="_blank" rel="noreferrer"><code>src/agents/atlas.ts</code></a></td><td>-</td></tr><tr><td>Oracle 顧問</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/oracle.ts" target="_blank" rel="noreferrer"><code>src/agents/oracle.ts</code></a></td><td>1-123</td></tr><tr><td>Librarian 研究專家</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/librarian.ts" target="_blank" rel="noreferrer"><code>src/agents/librarian.ts</code></a></td><td>1-327</td></tr><tr><td>Explore 搜尋專家</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/explore.ts" target="_blank" rel="noreferrer"><code>src/agents/explore.ts</code></a></td><td>1-123</td></tr><tr><td>Multimodal Looker</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/multimodal-looker.ts" target="_blank" rel="noreferrer"><code>src/agents/multimodal-looker.ts</code></a></td><td>1-57</td></tr><tr><td>Prometheus 規劃師</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/prometheus-prompt.ts" target="_blank" rel="noreferrer"><code>src/agents/prometheus-prompt.ts</code></a></td><td>1-1196</td></tr><tr><td>Metis 前規劃分析</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/metis.ts" target="_blank" rel="noreferrer"><code>src/agents/metis.ts</code></a></td><td>1-316</td></tr><tr><td>Momus 計畫審查者</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/momus.ts" target="_blank" rel="noreferrer"><code>src/agents/momus.ts</code></a></td><td>1-445</td></tr><tr><td>Sisyphus Junior</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/sisyphus-junior.ts" target="_blank" rel="noreferrer"><code>src/agents/sisyphus-junior.ts</code></a></td><td>-</td></tr><tr><td>代理元資料定義</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/types.ts" target="_blank" rel="noreferrer"><code>src/agents/types.ts</code></a></td><td>-</td></tr><tr><td>代理工具限制</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/shared/permission-compat.ts" target="_blank" rel="noreferrer"><code>src/shared/permission-compat.ts</code></a></td><td>-</td></tr></tbody></table><p><strong>關鍵設定</strong>：</p><ul><li><code>ORACLE_PROMPT_METADATA</code>：Oracle 代理的元資料（觸發條件、使用情境）</li><li><code>LIBRARIAN_PROMPT_METADATA</code>：Librarian 代理的元資料</li><li><code>EXPLORE_PROMPT_METADATA</code>：Explore 代理的元資料</li><li><code>MULTIMODAL_LOOKER_PROMPT_METADATA</code>：Multimodal Looker 代理的元資料</li><li><code>METIS_SYSTEM_PROMPT</code>：Metis 代理的系統提示詞</li><li><code>MOMUS_SYSTEM_PROMPT</code>：Momus 代理的系統提示詞</li></ul><p><strong>關鍵函式</strong>：</p><ul><li><code>createOracleAgent(model)</code>：建立 Oracle 代理設定</li><li><code>createLibrarianAgent(model)</code>：建立 Librarian 代理設定</li><li><code>createExploreAgent(model)</code>：建立 Explore 代理設定</li><li><code>createMultimodalLookerAgent(model)</code>：建立 Multimodal Looker 代理設定</li><li><code>createMetisAgent(model)</code>：建立 Metis 代理設定</li><li><code>createMomusAgent(model)</code>：建立 Momus 代理設定</li></ul><p><strong>權限限制</strong>：</p><ul><li><code>createAgentToolRestrictions()</code>：建立代理工具限制（Oracle、Librarian、Explore、Metis、Momus 使用）</li><li><code>createAgentToolAllowlist()</code>：建立代理工具白名單（Multimodal Looker 使用）</li></ul></details>`,160)])])}const h=s(n,[["render",r]]);export{u as __pageData,h as default};
